solution_code:
#include <iostream>

int add(int a, int b);
int multiply(int a, int b);
int combined(int a, int b);

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    std::cout << "Sum: " << add(a, b) << '\n';
    std::cout << "Product: " << multiply(a, b) << '\n';
    std::cout << "Combined: " << combined(a, b) << '\n';

    return 0;
}

int combined(int a, int b) {
    return add(a, b) + multiply(a, b);
}

int add(int a, int b) {
    return a + b;
}

int multiply(int a, int b) {
    return a * b;
}
